import { useEffect, useMemo, useRef, type FC } from "react";
import { useApp } from "../../state/AppContext";
import { useListboxNav } from "../../hooks/useListboxNav";
import type { PdfOperation, PdfValue } from "../../../shared/ir-types";

export const ContentView: FC = () => {
  const { state, dispatch } = useApp();
  const pageOps = state.pageOps;
  const operations = pageOps.status === "loaded" ? pageOps.result.operations : [];
  const selectedRef = useRef<HTMLLIElement | null>(null);
  const ids = operations.map((o) => o.id);
  const onKeyDown = useListboxNav({
    ids,
    selectedId: state.selectedNodeId,
    onSelect: (id) => dispatch({ type: "select", nodeId: id, origin: "tree" }),
  });

  // Scroll the selected row into view when selection moves to this page.
  // behavior: "auto" — CSS reduced-motion can't reach a JS smooth scroll,
  // and the motion-restraint skill says jumps like this should be
  // instantaneous in a DevTools-style UI anyway.
  useEffect(() => {
    if (state.selectionOrigin === "tree") return;
    selectedRef.current?.scrollIntoView({ block: "nearest", behavior: "auto" });
  }, [state.selectedNodeId, state.selectionOrigin]);

  // Compute q/Q + BT/ET indent levels for a compact timeline.
  const rows = useMemo(() => {
    let depth = 0;
    return operations.map((op) => {
      if (op.operator === "Q" || op.operator === "ET" || op.operator === "EMC")
        depth = Math.max(0, depth - 1);
      const row = { op, depth };
      if (
        op.operator === "q" ||
        op.operator === "BT" ||
        op.operator === "BMC" ||
        op.operator === "BDC"
      )
        depth++;
      return row;
    });
  }, [operations]);

  if (pageOps.status === "loading")
    return <div className="treepanel-empty">Parsing page content…</div>;
  if (pageOps.status === "error")
    return <div className="treepanel-empty">Error: {pageOps.error}</div>;
  if (operations.length === 0)
    return <div className="treepanel-empty">No content operators on this page.</div>;

  return (
    <ul
      className="treepanel-list"
      role="listbox"
      aria-label={`Content of page ${state.currentPage}`}
      aria-activedescendant={state.selectedNodeId}
      tabIndex={0}
      onKeyDown={onKeyDown}
    >
      {rows.map(({ op, depth: rowDepth }) => {
        const selected = state.selectedNodeId === op.id;
        return (
          <li
            ref={selected ? selectedRef : null}
            key={op.id}
            id={op.id}
            role="option"
            aria-selected={selected}
            tabIndex={-1}
            className="treepanel-row"
            data-testid={`tree-op-${op.sequence}`}
            data-selected={selected}
            onClick={() => dispatch({ type: "select", nodeId: op.id, origin: "tree" })}
          >
            <span className="treepanel-row-id" style={{ paddingLeft: rowDepth * 12 }}>
              {op.sequence}
            </span>
            <span className="treepanel-chip" data-kind={op.category}>
              {op.operator}
            </span>
            <span className="treepanel-row-hint">{formatOperands(op.operands)}</span>
          </li>
        );
      })}
    </ul>
  );
};

function formatOperands(operands: PdfOperation["operands"]): string {
  if (operands.length === 0) return "";
  return operands
    .slice(0, 4)
    .map(formatOperand)
    .concat(operands.length > 4 ? ["…"] : [])
    .join(" ");
}

function formatOperand(v: PdfValue): string {
  switch (v.kind) {
    case "int":
    case "real":
      return String(v.value);
    case "name":
      return `/${v.value}`;
    case "string":
      return "(…)";
    case "array":
      return "[…]";
    case "dict":
      return "<<…>>";
    case "ref":
      return v.target;
    case "bool":
      return String(v.value);
    case "null":
      return "null";
    case "stream":
      return "stream";
    default: {
      const _x: never = v;
      void _x;
      return "?";
    }
  }
}
